mapper.select:
select 
from drive_entry
where space_id = #{spaceId, jdbcType=BINARY}
  and entry_id = #{entryId, jdbcType=BINARY}

select 
from drive_entry
where space_id = #{spaceId, jdbcType=BINARY}
  and parent_key = #{parentKey}
  and active_name = #{name}
  and status = 'ACTIVE'
  and (
    (parent_id is null and #{parentId, jdbcType=BINARY} is null)
    or parent_id = #{parentId, jdbcType=BINARY}
  )

select 
from drive_entry
where space_id = #{spaceId, jdbcType=BINARY}
  and parent_key = #{parentKey}
  and status = 'ACTIVE'
  and (
    (parent_id is null and #{parentId, jdbcType=BINARY} is null)
    or parent_id = #{parentId, jdbcType=BINARY}
  )
order by case when type = 'FOLDER' then 0 else 1 end, name asc, entry_id asc
